interface CustomSelectProps {
  label: string;
  value: string | number;
  options: (string | number)[];
  onChange: (val: any) => void;
  placeholder: string;
  isInstitution?: boolean;
}

const CustomSelect: React.FC<CustomSelectProps> = ({ label, value, options, onChange, placeholder, isInstitution }) => {
  const [isOpen, setIsOpen] = useState(false);

  // Interaction Rule: No background scrolling while dropdown is open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
    };
  }, [isOpen]);

  const handleSelect = (option: any) => {
    onChange(option);
    setIsOpen(false);
  };

  return (
    <div className={`space-y-2 relative animate-fade-in ${isOpen ? 'z-[150]' : 'z-10'}`}>
      <label className={`text-sm font-bold ml-1 ${!isInstitution ? 'text-white/80' : 'text-slate-700'}`}>{label}</label>
      <div 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full p-4 rounded-xl border-2 cursor-pointer flex justify-between items-center transition-all font-medium ${
          isInstitution 
            ? 'bg-white border-slate-200 text-slate-900' 
            : 'bg-white/10 border-white/20 text-white'
        }`}
      >
        <span className={!value ? (isInstitution ? 'text-slate-400' : 'text-white/50') : ''}>
          {value || placeholder}
        </span>
        <svg 
          viewBox="0 0 24 24" 
          fill="none" 
          className={`w-5 h-5 transition-transform ${isOpen ? 'rotate-180' : ''}`} 
          stroke="currentColor" 
          strokeWidth="2.5" 
          strokeLinecap="round" 
          strokeLinejoin="round"
        >
          <path d="M6 9l6 6 6-6"></path>
        </svg>
      </div>

      {isOpen && (
        <>
          {/* Interaction Rule: Full-screen invisible backdrop to block interaction and close on outside click */}
          {/* Using a high z-index and fixed position to ensure it covers the entire screen and blocks siblings */}
          <div 
            className="fixed inset-0 z-[140] bg-white/0 pointer-events-auto cursor-default" 
            onClick={(e) => {
              e.stopPropagation();
              setIsOpen(false);
            }} 
          />
          {/* Implementation Rule: 100% Solid white dropdown sitting above UI */}
          <div 
            className="absolute left-0 right-0 mt-2 bg-white border-2 border-slate-200 rounded-xl shadow-[0_12px_40px_rgba(0,0,0,0.3)] z-[160] overflow-hidden pointer-events-auto ring-1 ring-slate-100 opacity-100"
            style={{ 
              backgroundColor: '#ffffff',
              opacity: 1
            }}
          >
            <div className="max-h-60 overflow-y-auto bg-white opacity-100">
              {options.map((option) => (
                <div
                  key={option}
                  onClick={() => handleSelect(option)}
                  className={`p-4 hover:bg-slate-50 transition-colors cursor-pointer text-slate-700 font-bold border-b border-slate-50 last:border-0 ${
                    value === option ? 'bg-blue-50 text-blue-700' : ''
                  }`}
                >
                  {typeof option === 'number' ? `Class ${option}` : option}
                </div>
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
};

